import azure.functions as func


def main(req: func.HttpRequest) -> func.HttpResponse:
    """
    Azure Function HTTP API endpoint for a single-page application.
    Handles various HTTP methods and returns appropriate responses with CORS headers.
    """
    logging.info('Python HTTP trigger function processed a request.')

    # Define CORS headers to allow requests from any origin
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, Accept, Origin",
        "Access-Control-Max-Age": "86400",
        "Access-Control-Expose-Headers": "Content-Length, X-Request-Id"
    }

    # Handle CORS preflight OPTIONS request
    if req.method == "OPTIONS":
        return func.HttpResponse(
            status_code=204,
            headers=cors_headers
        )

    try:
        # Route handling based on the 'action' route parameter or query parameter
        action = req.route_params.get('action', '') or req.params.get('action', '')

        if req.method == "GET":
            response_data = handle_get(req, action)
        elif req.method == "POST":
            response_data = handle_post(req, action)
        elif req.method == "PUT":
            response_data = handle_put(req, action)
        elif req.method == "DELETE":
            response_data = handle_delete(req, action)
        elif req.method == "PATCH":
            response_data = handle_patch(req, action)
        else:
            response_data = {
                "status": "error",
                "message": f"Unsupported HTTP method: {req.method}"
            }
            return func.HttpResponse(
                body=json.dumps(response_data),
                status_code=405,
                mimetype="application/json",
                headers=cors_headers
            )

        status_code = response_data.pop("_status_code", 200)

        return func.HttpResponse(
            body=json.dumps(response_data, default=str),
            status_code=status_code,
            mimetype="application/json",
            headers=cors_headers
        )

    except ValueError as ve:
        logging.error(f"Validation error: {str(ve)}")
        error_response = {
            "status": "error",
            "message": f"Invalid request: {str(ve)}"
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=400,
            mimetype="application/json",
            headers=cors_headers
        )

    except Exception as e:
        logging.error(f"Unhandled exception: {str(e)}")
        error_response = {
            "status": "error",
            "message": "Internal server error",
            "detail": str(e)
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=500,
            mimetype="application/json",
            headers=cors_headers
        )


def handle_get(req: func.HttpRequest, action: str) -> dict:
    """Handle GET requests - retrieve resources."""
    logging.info(f"Handling GET request for action: {action}")

    # Extract query parameters
    params = dict(req.params)

    if action == "items":
        # Example: return a list of items
        items = [
            {"id": 1, "name": "Item 1", "description": "First item"},
            {"id": 2, "name": "Item 2", "description": "Second item"},
            {"id": 3, "name": "Item 3", "description": "Third item"},
        ]

        # Support basic filtering via query params
        if "name" in params:
            items = [item for item in items if params["name"].lower() in item["name"].lower()]

        return {
            "status": "success",
            "data": items,
            "count": len(items)
        }

    elif action == "health":
        return {
            "status": "success",
            "message": "API is healthy",
            "version": "1.0.0"
        }

    elif action == "config":
        # Return non-sensitive SPA configuration
        return {
            "status": "success",
            "data": {
                "apiVersion": "1.0.0",
                "features": {
                    "darkMode": True,
                    "notifications": True,
                    "analytics": False
                },
                "pagination": {
                    "defaultPageSize": 20,
                    "maxPageSize": 100
                }
            }
        }

    else:
        return {
            "status": "success",
            "message": "SPA API is running. Use specific action endpoints.",
            "availableActions": ["items", "health", "config"],
            "method": "GET",
            "params": params
        }


def handle_post(req: func.HttpRequest, action: str) -> dict:
    """Handle POST requests - create resources."""
    logging.info(f"Handling POST request for action: {action}")

    # Parse request body
    try:
        request_body = req.get_json()
    except ValueError:
        request_body = None

    if not request_body:
        raise ValueError("Request body is required for POST requests and must be valid JSON.")

    if action == "items":
        # Validate required fields
        if "name" not in request_body:
            raise ValueError("'name' field is required to create an item.")

        new_item = {
            "id": 4,  # In production, this would be auto-generated
            "name": request_body.get("name"),
            "description": request_body.get("description", ""),
            "created": True
        }

        return {
            "status": "success",
            "message": "Item created successfully",
            "data": new_item,
            "_status_code": 201
        }

    elif action == "auth":
        # Example authentication endpoint
        username = request_body.get("username")
        password = request_body.get("password")

        if not username or not password:
            raise ValueError("'username' and 'password' are required.")

        # In production, validate credentials against a real auth provider
        return {
            "status": "success",
            "message": "Authentication successful",
            "data": {
                "token": "example-jwt-token-replace-with-real-auth",
                "expiresIn": 3600,
                "user": {
                    "username": username,
                    "role": "user"
                }
            }
        }

    else:
        return {
            "status": "success",
            "message": f"POST request received for action: {action or 'default'}",
            "receivedData": request_body,
            "_status_code": 201
        }


def handle_put(req: func.HttpRequest, action: str) -> dict:
    """Handle PUT requests - update resources."""
    logging.info(f"Handling PUT request for action: {action}")

    try:
        request_body = req.get_json()
    except ValueError:
        request_body = None

    if not request_body:
        raise ValueError("Request body is required for PUT requests and must be valid JSON.")

    item_id = req.params.get("id")

    if action == "items":
        if not item_id:
            raise ValueError("'id' query parameter is required to update an item.")

        updated_item = {
            "id": int(item_id),
            "name": request_body.get("name", "Updated Item"),
            "description": request_body.get("description", ""),
            "updated": True
        }

        return {
            "status": "success",
            "message": f"Item {item_id} updated successfully",
            "data": updated_item
        }

    else:
        return {
            "status": "success",
            "message": f"PUT request received for action: {action or 'default'}",
            "receivedData": request_body
        }


